from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)

@app.route("/login")
def login():
    # Redirect the user to the authorization server for login
    return redirect("https://authorization-server.com/oauth2/authorize?response_type=code&client_id=your_client_id&redirect_uri=http://localhost:5000/callback")

@app.route("/callback", methods=["GET"])
def callback():
    # Exchange the authorization code for an access token using requests.post()
    response = requests.post("https://authorization-server.com/oauth2/token", data={"grant_type": "authorization_code", "client_id": "your_client_id", "client_secret": "your_client_secret", "redirect_uri": "http://localhost:5000/callback", "code": request.args.get("code")})
    # Store the access token in the session
    session["access_token"] = response.json()["access_token"]
    return redirect("/")